import { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { setAuth } from "../../utils/auth";

function Login() {
  const [credentials, setCredentials] = useState({ email: "", password: "" });
  const navigate = useNavigate();

  const handleChange = (e) => {
    setCredentials({ ...credentials, [e.target.name]: e.target.value });
  };

  const submit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post("http://localhost:8070/api/auth/login", credentials);

      // ✅ this triggers navbar refresh
      setAuth({
        token: res.data.token,
        role: res.data.user.role,
        user: res.data.user,
      });

      alert("Login successful!");
      navigate("/vehicles");
    } catch (err) {
        console.log("LOGIN ERROR status:", err.response?.status);
        console.log("LOGIN ERROR data:", err.response?.data);
        console.log("LOGIN ERROR message:", err.message);

        alert(err.response?.data?.message || `Login failed (${err.response?.status || "no status"})`);    }
  };

  return (
    <div style={{ maxWidth: 400, margin: "50px auto", padding: 20, border: "1px solid #ddd", borderRadius: 8 }}>
      <h2>Login</h2>
      <form onSubmit={submit}>
        <input
          name="email"
          type="email"
          placeholder="Email"
          value={credentials.email}
          onChange={handleChange}
          required
          style={{ width: "100%", margin: "10px 0", padding: 10 }}
        />
        <input
          name="password"
          type="password"
          placeholder="Password"
          value={credentials.password}
          onChange={handleChange}
          required
          style={{ width: "100%", margin: "10px 0", padding: 10 }}
        />
        <button type="submit" style={{ width: "100%", padding: 10, marginTop: 10 }}>
          Login
        </button>
      </form>
    </div>
  );
}

export default Login;
